private IEnumerator SpawnMonster(float delay, int monsterNumber, int nextmonterNumber)
{
    while (true)
    {
        yield return new WaitForSeconds(delay);

        // 현재 티어 몬스터 스폰
        GameObject inactiveMonster = monsterPools[monsterNumber - 1]
            .Find(monster => !monster.activeSelf);
        if (inactiveMonster != null)
        {
            inactiveMonster.SetActive(true);
            inactiveMonster.transform.position = GetRandomSpawnPosition();
        }

        // 다음 티어 몬스터도 동시 스폰
        if (nextmonterNumber <= monsterPrefabs.Length - 1)
        {
            GameObject inactiveNextMonster = monsterPools[nextmonterNumber - 1]
                .Find(monster => !monster.activeSelf);
            if (inactiveNextMonster != null)
            {
                inactiveNextMonster.SetActive(true);
                inactiveNextMonster.transform.position = GetRandomSpawnPosition();
            }
        }
    }
}

void GenerateRandomObject()
{
    int[][] checkPos = new int[width][];
    for (int i = 0; i < width; i++)
        checkPos[i] = new int[height];

    for (int x = 0; x < width; x++)
    {
        for (int y = 0; y < height; y++)
        {
            if (checkPos[x][y] == 1) continue;

            if (Random.Range(0f, 100f) < spawnPercentage)
            {
                // spawndistance 범위 내 충돌 체크
                bool isValidPosition = true;
                for (int i = x; i < x + spawndistance; i++)
                    for (int j = y; j < y + spawndistance; j++)
                        if (i < width && j < height && checkPos[i][j] == 1)
                            isValidPosition = false;

                if (isValidPosition)
                {
                    int pickIndex = Random.Range(0, objectTile.Length);
                    layerIndex[1].SetTile(new Vector3Int(x, y, 0), objectTile[pickIndex]);

                    // 해당 범위 점유 표시
                    for (int i = x; i < x + spawndistance; i++)
                        for (int j = y; j < y + spawndistance; j++)
                            if (i < width && j < height)
                                checkPos[i][j] = 1;
                }
            }
        }
    }
}

public class PlayerState : MonoBehaviour
{
    public static float Defense;
    public static float Damage;
    public static float Hp;
    public static float Speed;

    [SerializeField] int CharacterIndex;

    private void Awake()
    {
        switch (CharacterIndex)
        {
            case 0:  // White - 밸런스형
                Hp = 200f;
                Speed = 3;
                Damage = 100;
                Defense = 0.8f;
                break;

            case 1:  // Blue - 유틸리티형
                Hp = 150f;
                Speed = 5;
                Damage = 150;
                Defense = 0.9f;
                break;

            case 2:  // Green - 고화력형
                Hp = 250;
                Speed = 4;
                Damage = 200;
                Defense = 0.6f;
                break;
        }
    }
}
